  font-size: 1rem;
}

.field {
  display: grid;
  gap: 6px;
  margin-bottom: 12px;
}

.field__label {
  font-size: 0.92rem;
  font-weight: 600;
}

.field__input {
  width: 100%;
  border: 1px solid rgba(16, 35, 58, 0.18);
  border-radius: 14px;
  padding: 10px 12px;
  background: var(--surface-strong);
  color: inherit;
}

.actions {
  display: flex;
  gap: 10px;
  flex-wrap: wrap;
}

.button {
  border: 1px solid rgba(16, 35, 58, 0.15);
  border-radius: 999px;
  background: rgba(255, 255, 255, 0.8);
  color: inherit;
  padding: 10px 16px;
  cursor: pointer;
}

.button:disabled {
  cursor: not-allowed;
  opacity: 0.45;
}

.button--primary {
  background: var(--accent);
  color: white;
  border-color: transparent;
}

.file-input {
  display: none;
}

.status-card,
.card {
  background: var(--surface-strong);
  border: 1px solid var(--border);
  border-radius: 20px;
  padding: 18px;
}

.status-card__row {
  display: flex;
  justify-content: space-between;
  gap: 12px;
  margin-bottom: 10px;
}

.progress-bar {
  height: 12px;
  border-radius: 999px;
  background: rgba(20, 87, 166, 0.12);
  overflow: hidden;
  margin: 14px 0 18px;
}

.progress-bar__fill {
  height: 100%;
  background: linear-gradient(90deg, var(--accent) 0%, var(--accent-strong) 100%);
}

.result-grid {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 16px;
  margin-top: 20px;
}

.viewer-layout {
  display: grid;
  grid-template-columns: minmax(0, 1fr) minmax(320px, 380px);
  gap: 16px;
  margin-top: 20px;
}

.card--map,
.card--viewer {
  display: flex;
  flex-direction: column;
}

.canvas-frame {
  margin-top: 14px;
  border-radius: 18px;
  overflow: hidden;
  background: #efe7d5;
  border: 1px solid rgba(16, 35, 58, 0.12);
}

.canvas {
  display: block;
  width: 100%;
  height: auto;
  background: #efe7d5;
}

.canvas--map {
  max-height: 480px;
  object-fit: contain;
}

.canvas--viewer {
  aspect-ratio: 1 / 1;
}

.metric {
  margin: 8px 0 0;
  font-weight: 600;
}

.metric--large {
  font-size: 1.4rem;
  line-height: 1.3;
}

.detail {
  margin: 8px 0 0;
  font-size: 0.92rem;
}

.ok {
  color: var(--ok);
}

.errors,
.notes {
  margin: 12px 0 0;
  padding-left: 18px;
}

.error-banner {
  margin: 12px 0 0;
  color: var(--error);
  font-weight: 600;
}

@media (max-width: 1100px) {
  .app-shell {
    grid-template-columns: 1fr;
  }

  .result-grid {
    grid-template-columns: 1fr;
  }

  .viewer-layout {
    grid-template-columns: 1fr;
  }
}

